<script>
function showError(msg){const b=document.getElementById('errorBanner');b.textContent=msg;b.classList.add('visible');setTimeout(()=>b.classList.remove('visible'),6000);}

let currentEntity = 'pvtltd';
let currentVolume = 'mid';

function setEntity(b){
    const e = b.closest ? (b.closest('.toggle-btn') || b) : b;
    currentEntity = e.dataset.entity;
    e.parentElement.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));
    e.classList.add('active');
    // Auto-toggle audit applicable for LLP (default off)
    const audit = document.getElementById('auditApplicable');
    if(currentEntity === 'llp'){
        // LLP: only mandatory above ₹40L turnover or ₹25L capital
        audit.checked = false;
    } else {
        audit.checked = true;
    }
}

function setVolume(b){
    const e = b.closest ? (b.closest('.toggle-btn') || b) : b;
    currentVolume = e.dataset.volume;
    e.parentElement.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));
    e.classList.add('active');
}

function formatINR(n){
    return n.toLocaleString('en-IN');
}

function calculate(){
    const turnover = parseInt(document.getElementById('turnoverBand').value);
    const directors = parseInt(document.getElementById('directors').value) || 2;
    const gstReg = document.getElementById('gstReg').checked;
    const auditApplicable = document.getElementById('auditApplicable').checked;
    const firstYear = document.getElementById('firstYear').checked;

    if(directors < 1 || directors > 15){
        showError('Number of directors must be between 1 and 15.');
        return;
    }

    const lines = [];

    // 1. ROC compliance
    if(currentEntity === 'pvtltd'){
        lines.push({label: 'ROC compliance — AOC-4, MGT-7, ADT-1, Director Report, Auditor Report', fee: 15000});
    } else if(currentEntity === 'opc'){
        lines.push({label: 'ROC compliance — AOC-4, MGT-7A, ADT-1, Director Report', fee: 12000});
    } else if(currentEntity === 'llp'){
        lines.push({label: 'ROC compliance — Form 8 (Statement of Account), Form 11 (Annual Return)', fee: 8000});
    } else if(currentEntity === 'section8'){
        lines.push({label: 'ROC compliance — AOC-4, MGT-7, ADT-1 + activity report', fee: 18000});
    }

    // 2. Statutory audit
    if(auditApplicable){
        let audFee = 12000;
        if(turnover === 2) audFee = 18000;
        else if(turnover === 3) audFee = 25000;
        else if(turnover === 4) audFee = 35000;
        else if(turnover === 5) audFee = 50000;
        lines.push({label: 'Statutory audit (' + (currentEntity === 'llp' ? 'LLP Act' : 'Companies Act') + ')', fee: audFee});

        // Tax audit (Section 44AB) if turnover > 1 Cr (band >= 2)
        if(turnover >= 2){
            let taxAudFee = 8000;
            if(turnover === 3) taxAudFee = 12000;
            else if(turnover >= 4) taxAudFee = 15000;
            lines.push({label: 'Tax audit under Section 44AB (Form 3CA/3CB + 3CD)', fee: taxAudFee});
        }
    }

    // 3. ITR
    let itrFee = 4000;
    let itrForm = 'ITR-6';
    if(currentEntity === 'llp'){ itrFee = 3500; itrForm = 'ITR-5'; }
    else if(currentEntity === 'section8'){ itrFee = 5000; itrForm = 'ITR-7'; }
    if(turnover === 3) itrFee += 2000;
    else if(turnover >= 4) itrFee += 4000;
    lines.push({label: 'Income tax return (' + itrForm + ')', fee: itrFee});

    // 4. GST
    if(gstReg){
        let monthlyGst = 1000;
        if(currentVolume === 'low') monthlyGst = 500;
        else if(currentVolume === 'high') monthlyGst = 2000;
        const annualGst = monthlyGst * 12;
        lines.push({label: 'GST monthly returns (GSTR-1, GSTR-3B) × 12 months', fee: annualGst});
        lines.push({label: 'GSTR-9 annual return', fee: 3500});
    }

    // 5. TDS
    lines.push({label: 'TDS quarterly returns (Form 24Q + 26Q) × 4 quarters', fee: 4000});

    // 6. DIR-3 KYC / Partner KYC
    if(currentEntity !== 'llp'){
        lines.push({label: 'DIR-3 KYC × ' + directors + ' director(s)', fee: 500 * directors});
    } else {
        lines.push({label: 'Designated Partner KYC × ' + directors + ' partner(s)', fee: 400 * directors});
    }

    // 7. DPT-3 (excluding LLP)
    if(currentEntity !== 'llp'){
        lines.push({label: 'DPT-3 (Return of Deposits)', fee: 1000});
    }

    // 8. Section 8 additional
    if(currentEntity === 'section8'){
        lines.push({label: '12A registration renewal (if due in this year)', fee: 2500});
        lines.push({label: '80G registration renewal (if due in this year)', fee: 2500});
        lines.push({label: 'Form 10BD donor statement (base only)', fee: 2000});
    }

    // 9. First-year extras
    if(firstYear){
        lines.push({label: 'First-year setup — books opening, accounting policy, INC-20A', fee: 5000});
    }

    const total = lines.reduce((sum, l) => sum + l.fee, 0);

    // Commodity provider quote: 35-50% of Patron
    const commodityLow = Math.round(total * 0.35 / 1000) * 1000;
    const commodityHigh = Math.round(total * 0.5 / 1000) * 1000;

    // Render itemised
    const tbody = document.getElementById('itemisedBody');
    tbody.innerHTML = '';
    lines.forEach(l => {
        const tr = document.createElement('tr');
        const td1 = document.createElement('td'); td1.textContent = l.label;
        const td2 = document.createElement('td'); td2.textContent = '₹' + formatINR(l.fee);
        tr.appendChild(td1); tr.appendChild(td2);
        tbody.appendChild(tr);
    });

    document.getElementById('resTotal').textContent = formatINR(total);
    document.getElementById('resTotalFoot').textContent = formatINR(total);
    document.getElementById('patronPrice').textContent = formatINR(total);
    document.getElementById('commodityPrice').textContent = formatINR(commodityLow) + '-' + formatINR(commodityHigh);

    // Build descriptive meta
    const entityLabels = {pvtltd: 'Private Limited', opc: 'One Person Company', llp: 'Limited Liability Partnership', section8: 'Section 8 Company'};
    const turnoverLabels = {1: 'up to ₹1 Cr', 2: '₹1-5 Cr', 3: '₹5-20 Cr', 4: '₹20-100 Cr', 5: 'above ₹100 Cr'};
    const volumeLabels = {low: 'low (under 50/mo)', mid: 'mid (50-200/mo)', high: 'high (200+/mo)'};
    document.getElementById('resMeta').textContent = entityLabels[currentEntity] + ' · ' + turnoverLabels[turnover] + ' turnover · ' + volumeLabels[currentVolume] + ' volume · ' + directors + ' director(s)' + (gstReg ? ' · GST registered' : '') + (auditApplicable ? ' · Audit applicable' : '') + (firstYear ? ' · First year' : '');

    const sec = document.getElementById('resultSection');
    sec.classList.add('visible');
    requestAnimationFrame(function(){requestAnimationFrame(function(){sec.scrollIntoView({behavior:'smooth',block:'start'});});});
}

function resetCalc(){
    currentEntity = 'pvtltd';
    currentVolume = 'mid';
    document.querySelectorAll('.toggle-group').forEach(g => g.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active')));
    document.querySelector('.toggle-btn[data-entity="pvtltd"]').classList.add('active');
    document.querySelector('.toggle-btn[data-volume="mid"]').classList.add('active');
    document.getElementById('turnoverBand').value = '2';
    document.getElementById('directors').value = '2';
    document.getElementById('gstReg').checked = true;
    document.getElementById('auditApplicable').checked = true;
    document.getElementById('firstYear').checked = false;
    document.getElementById('resultSection').classList.remove('visible');
    document.getElementById('errorBanner').classList.remove('visible');
}

function toggleFaq(e){const b=e.closest?(e.closest('.faq-question')||e):e;const it=b.closest('.faq-item');if(!it)return;const o=it.classList.contains('open');document.querySelectorAll('.faq-item').forEach(i=>{i.classList.remove('open');const q=i.querySelector('.faq-question');if(q)q.setAttribute('aria-expanded','false');});if(!o){it.classList.add('open');b.setAttribute('aria-expanded','true');}}

const navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',()=>{const s=document.querySelectorAll('section[id], header[id]');let c='';s.forEach(x=>{const t=x.offsetTop-100;if(window.pageYOffset>=t)c=x.getAttribute('id');});navLinks.forEach(l=>{l.classList.toggle('active',l.getAttribute('href')==='#'+c);});});
</script>


